        loop { yield_now().await; }
    });
    cx.cancel(CancelReason::User);
    let result = handle.join().await;
    assert!(matches!(result, Outcome::Cancelled(_)));
});

conformance_test!(outcome_panicked, |cx| {
    let result = cx.spawn(async {
        panic!("test panic");
    }).join().await;
    assert!(matches!(result, Outcome::Panicked(_)));
});
